// --- 洞穴蜘蛛 (tier1, chase) 16x14 ---
defineAnim('g_spider', 16, 14, 4, (p, f) => {
  const body = P.ink2, bodyL = P.purpleD, hairL = P.purple, hairLL = lighten(P.purple, 0.22);
  const legSwing = (f === 1 || f === 3) ? 1 : 0;
  const lift = (f === 2) ? -1 : 0;
  // 接地陰影 (隨抬腿微縮)
  p.softShadow(8, 13, 5 + (lift ? -0.5 : 0.5), 1.4, 0.34);
  // 8 條腳 (先畫左半再鏡射) — 加關節亮點顯立體
  for (let i = 0; i < 4; i++) {
    const ly = 6 + i * 1.6 + lift;
    const bend = (i % 2 === legSwing % 2) ? 1 : -1;
    p.line(6, 7 + lift, 2, ly - bend, P.ink);
    p.line(2, ly - bend, 0, ly + 1, P.ink);
    p.px(2, ly - bend, darken(hairL, 0.2)); // 膝關節
  }
  // 後腹部 (圓胖) — 三階明暗 + 鏡面
  p.ellipse(8, 9 + lift, 4.5, 4, body);
  p.ellipse(8, 8 + lift, 3.5, 3, bodyL);
  p.ellipse(7, 7 + lift, 1.8, 1.4, hairL);
  p.px(6, 6 + lift, hairLL); // 高光鱗光
  p.speckle(5, 7 + lift, 6, 4, withAlpha(P.purpleL, 0.5), 4, 7); // 絨毛斑點
  // 背上沙漏紋 (危險紅) + 微光
  p.px(8, 7 + lift, P.redL); p.px(8, 9 + lift, P.redL); p.px(8, 8 + lift, P.red);
  // 頭胸部 (小，前方)
  p.ellipse(8, 4 + lift, 3, 2.5, darken(body, 0.1));
  p.ellipse(8, 3.5 + lift, 2, 1.6, body);
  p.px(7, 2 + lift, withAlpha(hairL, 0.6)); // 頭胸高光
  // 多眼 (左側，鏡射成對) — 發光紅眼
  p.glow(6, 3 + lift, 1.6, P.ember, 0.5, 3);
  p.px(6, 3 + lift, P.redL); p.px(7, 4 + lift, P.red);
  p.px(6, 4 + lift, P.ember);
  p.px(6, 3 + lift, P.white); // catch-light
  // 螯牙
  p.px(7, 6 + lift, P.bone);
  p.px(7, 7 + lift, withAlpha(P.toxic, 0.6)); // 毒滴
  p.mirrorX();
  p.rimLight(P.rimCool, 0.45);
  p.outline(P.ink);
}, { anchor: [8, 13], fps: 7 });

// --- 灰狼 (tier2, charger) 18x16 ---
defineAnim('g_wolf', 18, 16, 4, (p, f) => {
  const fur = P.gray2, furD = P.gray1, furL = P.gray3, belly = P.gray4;
  const furLL = lighten(P.gray3, 0.18);
  const gait = [0, 1, 0, -1][f % 4];
  const breathe = (f % 2 === 0) ? 0 : 1; // 衝刺起伏
  // 接地陰影
  p.softShadow(9, 15, 7, 1.4, 0.32);
  // 後腿
  p.rect(3, 12, 2, 4, furD); p.rect(3, 15, 3, 1, P.ink);
  p.rect(13 - gait, 12, 2, 4, furD); p.rect(13 - gait, 15, 3, 1, P.ink);
  // 前腿
  p.rect(6 + gait, 12, 2, 4, fur); p.rect(6 + gait, 15, 3, 1, P.ink);
  p.rect(10, 12, 2, 4, fur); p.rect(10, 15, 3, 1, P.ink);
  // 身軀 — 四階明暗
  p.ellipse(9, 9 - breathe * 0.3, 7, 3.5, furD);
  p.ellipse(9, 8 - breathe * 0.3, 6, 3, fur);
  p.hline(4, 13, 11, belly);
  p.ellipse(8, 7, 3, 1.6, furL); // 背脊亮面
  p.ellipse(7, 6, 1.6, 0.9, furLL); // 鏡面光澤
  p.speckle(5, 8, 9, 3, withAlpha(furD, 0.4), 5, 11); // 毛流質感
  // 尾巴 (隨步態翹擺)
  const tail = (f % 2 === 0) ? -1 : 0;
  p.line(2, 8, 0, 5 + tail, furD); p.ellipse(1, 6 + tail, 1.6, 2, fur);
  p.px(0, 5 + tail, furL);
  // 頭 (右前)
  p.ellipse(15, 7, 3, 3, fur);
  p.ellipse(16, 8, 2, 1.6, belly); // 口鼻
  p.px(14, 5, furL); // 額頭亮面
  p.px(17, 8, P.ink); // 鼻頭
  // 耳朵 (警戒豎起)
  p.line(14, 4, 13, 1, furD); p.line(16, 4, 17, 1, furD);
  p.px(14, 3, fur); p.px(16, 3, fur);
  p.px(13, 1, withAlpha(P.sakuraD, 0.5)); p.px(17, 1, withAlpha(P.sakuraD, 0.5)); // 耳內粉
  // 眼 (兇，發光琥珀)
  p.glow(14, 6, 1.8, P.ember, 0.5, 3);
  p.px(15, 6, P.emberL); p.rect(14, 6, 1, 1, P.ember);
  p.px(15, 6, P.glint); // catch-light
  // 獠牙
  p.px(16, 9, P.white);
  p.px(15, 10, withAlpha(P.bone, 0.7));
  p.rimLight(P.rim, 0.5);
  p.outline(P.ink);
}, { anchor: [9, 15], fps: 8 });

// --- 沙蠍 (tier2, shooter) 18x14 ---
defineAnim('g_scorpion', 18, 14, 4, (p, f) => {
  const sh = P.bronze, shD = P.woodD, shL = P.goldL, shLL = lighten(P.goldL, 0.18);
  const sting = [0, -1, -2, -1][f % 4]; // 尾巴上下擺
  const charge = (sting <= -2); // 蓄毒幀
  // 接地陰影
  p.softShadow(8, 13, 5.5, 1.2, 0.3);
  // 腳 (左右各3) — 關節點
  for (let i = 0; i < 3; i++) {
    const lx = 6 + i * 2;
    p.line(lx, 9, lx - 3, 12, shD);
    p.line(18 - lx, 9, 18 - lx + 3, 12, shD);
    p.px(lx - 3, 12, P.ink); p.px(18 - lx + 3, 12, P.ink);
  }
  // 身軀分節 — 三階甲殼 + 鏡面
  p.ellipse(8, 8, 4, 2.6, shD);
  p.ellipse(8, 7.5, 3.2, 2, sh);
  p.hline(5, 11, 6, shL);
  p.px(6, 6, shLL); p.px(9, 6, withAlpha(shL, 0.7)); // 殼面高光
  // 頭
  p.ellipse(4, 8, 2, 1.8, sh);
  // 眼 (發光紅)
  p.glow(3, 7, 1.2, P.ember, 0.45, 3);
  p.px(3, 7, P.ink); p.px(4, 7, P.red);
  p.px(3, 7, withAlpha(P.emberL, 0.9));
  // 大螯 (前方左右)
  p.ellipse(2, 6, 1.6, 1.4, shD); p.line(1, 5, 0, 4, sh); p.px(1, 5, shL);
  p.ellipse(2, 10, 1.6, 1.4, shD); p.line(1, 11, 0, 12, sh); p.px(1, 11, shL);
  // 尾巴 (向上彎曲，分節)
  p.line(11, 7, 14, 6 + sting, shD);
  p.ellipse(13, 6 + sting, 1.4, 1.4, sh);
  p.line(14, 6 + sting, 16, 3 + sting, shD);
  p.ellipse(15, 4 + sting, 1.3, 1.3, sh);
  p.px(15, 3 + sting, shL); // 尾節高光
  // 毒針 + 毒液光 (蓄毒幀更亮)
  p.glow(16, 2 + sting, charge ? 2.4 : 1.6, P.toxic, charge ? 0.6 : 0.4, 3);
  p.px(16, 2 + sting, P.poison);
  p.px(16, 3 + sting, P.toxic);
  p.ellipse(16, 2 + sting, 1, 1, P.poison);
  p.px(16, 2 + sting, P.white);
  if (charge) { p.sparkle(16, 2 + sting, withAlpha(P.toxic, 0.7), 1); }
  p.rimLight(P.rim, 0.45);
  p.outline(P.ink);
}, { anchor: [9, 13], fps: 6 });

// --- 劇毒蛾 (tier1, flyer) 重用 drawBat 改毒綠 16x12 ---
defineAnim('g_venommoth', 16, 12, 2, (p, f) => {
  drawBat(p, f, P.poison, P.poisonD, P.purpleL);
  const up = f % 2 === 0;
  // 翅上毒斑與鱗粉 (發光眼斑)
  if (up) {
    p.glow(3, 5, 1.4, P.toxic, 0.4, 3); p.glow(13, 5, 1.4, P.toxic, 0.4, 3);
    p.px(3, 5, P.toxic); p.px(13, 5, P.toxic);
    p.px(2, 4, P.white); p.px(14, 4, P.white);
    p.px(4, 6, withAlpha(P.purpleL, 0.6)); p.px(12, 6, withAlpha(P.purpleL, 0.6));
  } else {
    p.glow(3, 8, 1.2, P.toxic, 0.35, 3); p.glow(13, 8, 1.2, P.toxic, 0.35, 3);
    p.px(3, 8, P.toxic); p.px(13, 8, P.toxic);
  }
  // 飄散鱗粉 (毒霧粒子，確定性)
  p.speckle(2, 2, 12, 8, withAlpha(P.toxic, 0.4), 4, up ? 3 : 9);
  // 觸角 (羽狀) + 發光大眼
  p.px(7, 2, P.poisonD); p.px(9, 2, P.poisonD);
  p.px(6, 1, withAlpha(P.poisonD, 0.6)); p.px(10, 1, withAlpha(P.poisonD, 0.6));
  p.glow(7, 6, 1, P.emberL, 0.4, 2); p.glow(9, 6, 1, P.emberL, 0.4, 2);
  p.px(7, 6, P.emberL); p.px(9, 6, P.emberL);
  p.rimLight(P.rimCool, 0.4);
  p.outline(P.ink);
}, { anchor: [8, 8], fps: 9 });

// --- 獠牙野豬 (tier3, charger) 20x16 ---
defineAnim('g_boar', 20, 16, 4, (p, f) => {
  const hide = P.woodD, hideL = P.wood, hideD = darken(P.woodD, 0.25), bristle = P.ink2;
  const hideLL = lighten(P.wood, 0.16);
  const gait = [0, 1, 0, -1][f % 4];
  const charge = (f % 2 === 0); // 衝撞起伏
  // 接地陰影 + 衝刺塵
  p.softShadow(10, 15, 8.5, 1.5, 0.34);
  if (charge) { p.speckle(1, 13, 4, 3, withAlpha(P.sandL || P.bone, 0.4), 3, 5); }
  // 腿 (粗壯4條)
  p.rect(4, 12, 3, 4, hideD); p.rect(4, 15, 3, 1, P.ink);
  p.rect(14 + gait, 12, 3, 4, hideD); p.rect(14 + gait, 15, 3, 1, P.ink);
  p.rect(7 - gait, 12, 3, 4, hide); p.rect(11, 12, 3, 4, hide);
  // 龐大身軀 — 四階明暗
  p.ellipse(10, 8 - (charge ? 0 : 0.3), 8, 5, hideD);
  p.ellipse(10, 7 - (charge ? 0 : 0.3), 7, 4.5, hide);
  p.ellipse(9, 5, 4, 2, hideL); // 背亮面
  p.ellipse(8, 4, 2, 1, hideLL); // 鏡面光澤
  p.speckle(5, 7, 10, 4, withAlpha(hideD, 0.35), 6, 13); // 皮質紋
  // 鬃毛 (背脊豎立，光照微亮)
  for (let x = 5; x <= 14; x += 2) { p.vline(2, 4, x, bristle); p.px(x, 2, withAlpha(P.gray4, 0.4)); }
  // 頭 (右側，低垂衝撞姿)
  p.ellipse(16, 9, 4, 3.5, hide);
  p.ellipse(18, 10, 2.5, 2, hideL); // 豬鼻
  p.px(15, 6, hideLL); // 額頭高光
  p.px(18, 10, P.ink); p.px(19, 10, P.ink); // 鼻孔
  // 耳
  p.line(15, 6, 14, 4, hideD); p.px(15, 5, hide);
  // 紅眼 (狂暴發光)
  p.glow(16, 8, 1.8, P.ember, 0.55, 3);
  p.px(16, 8, P.red); p.px(17, 8, P.emberL);
  p.px(16, 8, P.glint); // catch-light
  // 獠牙 (向上翹的白獠) — 加高光
  p.line(18, 11, 19, 8, P.bone); p.px(19, 7, P.white);
  p.line(17, 12, 17, 10, P.bone); p.px(19, 8, withAlpha(P.glint, 0.8));
  // 鼻孔噴氣 (衝刺幀)
  if (charge) { p.px(19, 11, withAlpha(P.white, 0.4)); p.px(19, 12, withAlpha(P.white, 0.25)); }
  p.rimLight(P.rim, 0.5);
  p.outline(P.ink);
}, { anchor: [10, 15], fps: 8 });

// --- 劇毒巨蟾 (tier3, shooter) 18x15 ---
defineAnim('g_toad', 18, 15, 4, (p, f) => {
  const skin = P.greenD, skinL = P.green, skinD = darken(P.greenD, 0.25), warty = P.poisonD;
  const skinLL = lighten(P.green, 0.18);
  const puff = [0, 1, 2, 1][f % 4]; // 鳴囊鼓動
  const full = (puff >= 2); // 滿氣幀 (準備吐毒)
  // 接地陰影
  p.softShadow(9, 14, 8, 1.4, 0.32);
  // 後腿 (蹲伏外張)
  p.ellipse(3, 12, 2.5, 2, skinD); p.ellipse(15, 12, 2.5, 2, skinD);
  p.line(2, 13, 0, 14, skinD); p.line(16, 13, 18, 14, skinD);
  // 前腳
  p.rect(5, 12, 2, 3, skin); p.rect(11, 12, 2, 3, skin);
  p.px(4, 14, skinD); p.px(13, 14, skinD);
  // 寬胖身軀 — 三階濕潤皮膚 + 鏡面
  p.ellipse(9, 9, 8, 5, skinD);
  p.ellipse(9, 8.5, 7, 4.3, skin);
  p.ellipse(8, 6, 3, 1.6, skinL); // 背亮面
  p.ellipse(7, 5, 1.4, 0.8, skinLL); // 濕潤鏡面光
  p.speckle(4, 7, 10, 4, withAlpha(skinD, 0.4), 6, 17); // 皮膚斑點
  // 鳴囊 (前下方鼓起) — 滿氣時微微透光
  p.ellipse(9, 11 + puff * 0.3, 3 + puff * 0.5, 2 + puff * 0.4, skinL);
  p.ellipse(9, 11 + puff * 0.3, 2, 1.2, lighten(skinL, 0.2));
  if (full) { p.glow(9, 11, 2.4, P.toxic, 0.35, 3); }
  // 疣突 (毒突發光)
  p.px(5, 6, warty); p.px(12, 7, warty); p.px(7, 5, warty); p.px(11, 5, warty); p.px(13, 9, warty);
  p.px(5, 6, P.toxic); p.px(11, 5, P.toxic);
  p.px(13, 9, withAlpha(P.toxic, 0.6));
  // 大眼凸 (頭頂兩側) — 發光圓眼 + 高光
  p.glow(5, 4, 1.8, P.ember, 0.45, 3); p.glow(13, 4, 1.8, P.ember, 0.45, 3);
  p.ellipse(5, 4, 2, 2, skinL); p.ellipse(13, 4, 2, 2, skinL);
  p.px(5, 4, P.emberL); p.px(13, 4, P.emberL);
  p.px(5, 4, P.ink); p.px(13, 4, P.ink);
  p.px(4, 3, P.white); p.px(12, 3, P.white); // catch-light
  // 寬嘴
  p.hline(6, 12, 8, skinD);
  // 滿氣幀: 嘴角毒滴
  if (full) { p.px(9, 9, withAlpha(P.toxic, 0.7)); p.sparkle(9, 11, withAlpha(P.toxic, 0.6), 1); }
  p.rimLight(P.rimCool, 0.45);
  p.outline(P.ink);
}, { anchor: [9, 14], fps: 5 });
